import { Injectable, inject } from '@angular/core';
import { SupabaseService } from './Base/supabase.service';
import { BehaviorSubject } from 'rxjs';
import { AuthService } from './Base/auth.service';

// Interfacce pubbliche (da spostare in models.ts o public-models.ts)
export interface PublicRestaurant {
  id: string;
  name: string;
  description?: string;
  address?: string;
  province?: string;
  city?: string;
  phone?: string;
  email?: string;
  logo_url?: string;
  cover_image_url?: string;
  accepts_delivery: boolean;
  accepts_takeaway: boolean;
  owner_id: string;                
  allow_table_selection: boolean;
  is_active: boolean;
  created_at?: string;
  updated_at?: string;
  latitude?: number;
  longitude?: number;
      additional_info?: {
    parking?: string;
    accepted_payments?: string[];
    wifi?: {
      ssid?: string;
      password?: string;
    };
    food_info?: {
      vegan?: boolean;
      gourmet?: boolean;
      fish?: boolean;
      meat?: boolean;
    };
    cuisine_types?: string[]; 
  };

}

export interface PublicShift {
  id: string;
  name: string;
  start_time: string;
  end_time: string;
  days_of_week: number[];
  is_active: boolean;
}

export interface PublicDish {
  id: string;
  name: string;
  description?: string | null;
  base_price: number;
  delivery_price?: number | null;
  takeaway_price?: number | null;
  image_url?: string | null;
  preparation_time?: number | null;
  status: 'available' | 'unavailable' | 'out_of_stock';
  category_id?: string | null;
  category_name?: string;
}

export interface PublicCategory {
  id: string;
  name: string;
  description?: string | null;
  order_index: number;
}

export interface PublicMenu {
  id: string;
  name: string;
  description?: string;
  is_default: boolean;
  is_active: boolean;
  type: 'global' | 'dedicated';
  display_order: number;
  fixed_price?: number | null; 
}

@Injectable({
  providedIn: 'root'
})
export class RestaurantPublicService {
  private supabaseService = inject(SupabaseService);
  private auth = inject(AuthService);
  private restaurantSubject = new BehaviorSubject<PublicRestaurant | null>(null);
  public restaurant$ = this.restaurantSubject.asObservable();

  // ==================== RISTORANTE ====================
  async loadRestaurantById(restaurantId: string): Promise<PublicRestaurant | null> {
    try {
      const supabase = this.supabaseService.getSupabaseClient();
      const { data, error } = await supabase
        .from('restaurants')
        .select('*')
        .eq('id', restaurantId)
        .eq('is_active', true)
        .single();
      if (error) throw error;

      if (data) {
        // Se c'è un logo, genera l'URL pubblico
        if (data.logo_url) {
  if (!data.logo_url.startsWith('http')) {
    const { data: { publicUrl } } = supabase.storage
      .from('restaurant-images')
      .getPublicUrl(data.logo_url);
    data.logo_url = publicUrl;
  }
  // altrimenti, lascia invariato (è già un URL completo)
}
        // Stessa cosa per cover_image_url se usata
        if (data.cover_image_url) {
          const { data: { publicUrl } } = supabase.storage
            .from('restaurant-images')
            .getPublicUrl(data.cover_image_url);
          data.cover_image_url = publicUrl;
        }
      }
      return data;
    } catch (error) {
      console.error('❌ Error loading restaurant by ID:', error);
      return null;
    }
  }

  async loadRestaurant(restaurantId: string): Promise<PublicRestaurant | null> {
    const data = await this.loadRestaurantById(restaurantId);
    this.restaurantSubject.next(data);
    return data;
  }

  async loadRestaurantsByCuisine(cuisineType?: string): Promise<PublicRestaurant[]> {
    try {
      let query = this.supabaseService.getSupabaseClient()
        .from('restaurants')
        .select('*')
        .eq('is_active', true)
        .order('name');
      if (cuisineType) query = query.eq('cuisine_types', cuisineType);
      const { data, error } = await query;
      if (error) throw error;
      return data || [];
    } catch (error) {
      console.error('❌ Error loading restaurants:', error);
      return [];
    }
  }

  // ==================== TURNI ====================
  async loadRestaurantShifts(restaurantId: string): Promise<PublicShift[]> {
    try {
      const { data, error } = await this.supabaseService.getSupabaseClient()
        .from('shifts')
        .select('*')
        .eq('restaurant_id', restaurantId)
        .eq('is_active', true)
        .order('start_time');
      if (error) throw error;
      return data || [];
    } catch (error) {
      console.error('❌ Error loading restaurant shifts:', error);
      return [];
    }
  }

  // ==================== PIATTI ====================
  async loadRestaurantDishes(
    restaurantId: string,
    options: { includeCategories?: boolean; onlyActive?: boolean } = {}
  ): Promise<PublicDish[]> {
    const { includeCategories = false, onlyActive = true } = options;
    try {
      let query = this.supabaseService.getSupabaseClient()
        .from('dishes')
        .select(`
          id,
          name,
          description,
          base_price,
          delivery_price,
          takeaway_price,
          image_url,
          preparation_time,
          status,
          category_id,
          categories ( id, name )
        `)
        .eq('restaurant_id', restaurantId);

      if (onlyActive) {
        query = query.eq('status', 'available');
      }

      const { data, error } = await query.order('name');
      if (error) throw error;

      // Mappa i dati – anche se TypeScript non riconosce la struttura, noi la costruiamo manualmente
      return (data as any[] || []).map((item) => {
        const dish: PublicDish = {
          id: item.id,
          name: item.name,
          description: item.description,
          base_price: item.base_price,
          delivery_price: item.delivery_price,
          takeaway_price: item.takeaway_price,
          image_url: item.image_url,
          preparation_time: item.preparation_time,
          status: item.status,
          category_id: item.category_id,
        };
        if (includeCategories && item.categories && item.categories.length > 0) {
          dish.category_name = item.categories[0].name;
        }
        return dish;
      });
    } catch (error) {
      console.error('❌ Error loading restaurant dishes:', error);
      return [];
    }
  }

  // ==================== CATEGORIE ====================
  async loadRestaurantCategories(restaurantId: string): Promise<PublicCategory[]> {
    try {
      const { data, error } = await this.supabaseService.getSupabaseClient()
        .from('categories')
        .select('*')
        .eq('restaurant_id', restaurantId)
        .order('order_index');
      if (error) throw error;
      return data || [];
    } catch (error) {
      console.error('❌ Error loading restaurant categories:', error);
      return [];
    }
  }

  // ==================== FOTO ====================
  async loadRestaurantPhotos(restaurantId: string): Promise<string[]> {
    try {
      const supabase = this.supabaseService.getSupabaseClient();
      const { data, error } = await supabase
        .from('restaurant_photos')
        .select('file_path')
        .eq('restaurant_id', restaurantId)
        .order('display_order', { ascending: true });
      if (error) throw error;

      return (data || []).map(photo =>
        supabase.storage.from('restaurant-images').getPublicUrl(photo.file_path).data.publicUrl
      );
    } catch (error) {
      console.error('❌ Error loading restaurant photos:', error);
      return [];
    }
  }

  // ==================== MENU ====================
  async loadRestaurantMenus(restaurantId: string): Promise<PublicMenu[]> {
    try {
      const { data, error } = await this.supabaseService.getSupabaseClient()
        .from('menus')
        .select('*')
        .eq('restaurant_id', restaurantId)
        .eq('is_active', true)
        .order('display_order');
      if (error) throw error;
      return data || [];
    } catch (error) {
      console.error('❌ Error loading restaurant menus:', error);
      return [];
    }
  }

async loadMenuDishes(menuId: string): Promise<PublicDish[]> {
  try {
    const { data, error } = await this.supabaseService.getSupabaseClient()
      .from('menu_dishes')
      .select(`
        custom_price,
        dish:dishes!dish_id (
          id, name, description, base_price, delivery_price,
          takeaway_price, image_url, preparation_time, status, category_id
        )
      `)
      .eq('menu_id', menuId)
      .eq('is_active', true)
      .order('display_order');

    if (error) throw error;

    return (data || [])
      .filter((item: any) => item.dish && !item.dish.deleted_at)
      .map((item: any) => ({
        ...item.dish,
        // Se c'è un prezzo custom nel menu, sovrascrive il base_price
        base_price: item.custom_price ?? item.dish.base_price
      }));

  } catch (error) {
    console.error('❌ Error loading menu dishes:', error);
    return [];
  }
}

  async loadActiveMenuDishes(restaurantId: string): Promise<PublicDish[]> {
    try {
      const supabase = this.supabaseService.getSupabaseClient();
      const { data: menus, error: menusError } = await supabase
        .from('menus')
        .select('id')
        .eq('restaurant_id', restaurantId)
        .eq('is_active', true);
      if (menusError) throw menusError;
      if (!menus?.length) return [];

      const menuIds = menus.map(m => m.id);
      const { data, error } = await supabase
        .from('menu_dishes')
        .select(`
          dish:dishes!dish_id (
            id, name, description, base_price, delivery_price,
            takeaway_price, image_url, preparation_time, status, category_id
          )
        `)
        .in('menu_id', menuIds)
        .eq('is_active', true);
      if (error) throw error;

      const dishesMap = new Map<string, PublicDish>();
      (data || []).forEach((item: any) => {
        if (item.dish && !item.dish.deleted_at && item.dish.status === 'available') {
          dishesMap.set(item.dish.id, item.dish);
        }
      });
      return Array.from(dishesMap.values());
    } catch (error) {
      console.error('❌ Error loading active menu dishes:', error);
      return [];
    }
  }

  // ==================== MAPPE ====================
  async getRestaurantFloorPlans(restaurantId: string): Promise<{ id: string; name: string }[]> {
    try {
      const { data, error } = await this.supabaseService.getSupabaseClient()
        .from('restaurant_floor_plans')
        .select('id, name')
        .eq('restaurant_id', restaurantId)
        .eq('is_active', true)
        .order('name');
      if (error) throw error;
      return data || [];
    } catch (error) {
      console.error('❌ Error loading floor plans:', error);
      return [];
    }
  }

    // ==================== METODI PER IL PROFILO (SCRITTURA) ====================

  /**
   * Ottiene l'ID del ristorante dell'utente attualmente loggato (tramite AuthService)
   */
  async getCurrentRestaurantId(): Promise<string | null> {
    return this.auth.getCurrentStaffRestaurantId();
  }

  /**
   * Carica i dati del ristorante dell'utente loggato
   */
  async loadCurrentRestaurant(): Promise<PublicRestaurant | null> {
    const restaurantId = await this.getCurrentRestaurantId();
    if (!restaurantId) return null;
    return this.loadRestaurantById(restaurantId);
  }

  /**
   * Aggiorna i dati del ristorante (solo i campi passati in `data`)
   */
async updateRestaurant(restaurantId: string, data: Partial<PublicRestaurant>): Promise<boolean> {
  try {
    const supabase = this.supabaseService.getSupabaseClient();
    const { error } = await supabase
      .from('restaurants')
      .update({ ...data, updated_at: new Date().toISOString() })
      .eq('id', restaurantId);
    if (error) {
      console.error('❌ Supabase update error:', error);
      throw error;
    }

      // Aggiorna il BehaviorSubject locale
      const current = this.restaurantSubject.value;
      if (current && current.id === restaurantId) {
        this.restaurantSubject.next({ ...current, ...data });
      } else {
        await this.loadRestaurant(restaurantId); // ricarica se non era quello corrente
      }
      return true;
    } catch (error) {
      console.error('❌ Error updating restaurant:', error);
      return false;
    }
  }

  /**
   * Carica un nuovo logo per il ristorante corrente
   */
  async uploadLogo(file: File): Promise<string | null> {
    const restaurantId = await this.getCurrentRestaurantId();
    if (!restaurantId) return null;

    const supabase = this.supabaseService.getSupabaseClient();
    const path = `restaurants/${restaurantId}/logos/${Date.now()}_${file.name}`;

    try {
      const { error: uploadError } = await supabase.storage
        .from('restaurant-images')
        .upload(path, file, { upsert: true });
      if (uploadError) throw uploadError;

      const { data: { publicUrl } } = supabase.storage
        .from('restaurant-images')
        .getPublicUrl(path);

      const success = await this.updateRestaurant(restaurantId, { logo_url: publicUrl });
      return success ? publicUrl : null;
    } catch (error) {
      console.error('❌ Error uploading logo:', error);
      return null;
    }
  }

  /**
   * Rimuove il logo del ristorante corrente (setta logo_url = null)
   */
  async removeLogo(): Promise<boolean> {
    const restaurantId = await this.getCurrentRestaurantId();
    if (!restaurantId) return false;
    return this.updateRestaurant(restaurantId, { logo_url: null as any });
  }

  /**
 * Geocodifica un indirizzo utilizzando l'API Nominatim di OpenStreetMap
 * @param address Indirizzo (es. "Via Roma 123")
 * @param province Sigla della provincia (es. "MI")
 * @returns Oggetto con latitudine e longitudine, oppure null se fallisce
 */
async geocodeAddress(address: string, province: string): Promise<{ lat: number; lng: number } | null> {
  if (!address || !province) return null;

  // Costruisci la query completa (indirizzo, provincia, Italia)
  const query = encodeURIComponent(`${address}, ${province}, Italia`);
  const url = `https://nominatim.openstreetmap.org/search?format=json&q=${query}&limit=1`;

  try {
    const response = await fetch(url, {
      headers: {
        'User-Agent': 'Platea/1.0' // Identifica la tua applicazione
      }
    });
    const data = await response.json();
    if (Array.isArray(data) && data.length > 0) {
      const { lat, lon } = data[0];
      return { lat: parseFloat(lat), lng: parseFloat(lon) };
    }
    return null;
  } catch (error) {
    console.error('❌ Errore geocoding:', error);
    return null;
  }
}

}